423	export async function fetchBuyers(limit = -1): Promise<Buyer[]> {
424	  // Filtering/ordering this security_invoker view through PostgREST can time out
425	  // because company_customer_status/name are derived across joined RLS tables.
426	  // Pull the browser-safe rows unfiltered and let the client segment/sort them.
427	  const rows = await fetchRows('crm_contact_list', [], limit)
428	  return rows
429	    .filter((r) => CUSTOMER_STATUSES.includes((r.company_customer_status ?? '') as string))
430	    .map(toBuyer)
431	}
